export default {
  title: 'Components/Timeline/临时示例',
  component: Timeline,
};

export const BasicUsage = () => {
  const sizeChangeProps = SizeChange.useState();
  const [mode, setMode] = React.useState<TimelineModeType>('left');
  const [lp, setLp] = React.useState<TimelineLabelPosition>('relative');
  const [reverse, seReverse] = React.useState<boolean>(false);
  return (
    <Space style={{ width: '100%' }} direction="vertical" size="large">
      <Space size="large" wrap>
        <SizeChange {...sizeChangeProps} />
        <Space>
          <span>mode：</span>
          <Radio.Group value={mode} onChange={value => setMode(value as TimelineModeType)}>
            <Radio.Button value="left">Left</Radio.Button>
            <Radio.Button value="right">Right</Radio.Button>
            <Radio.Button value="alternate">Alternate</Radio.Button>
          </Radio.Group>
        </Space>
        <Space>
          <span>labelPosition：</span>
          <Radio.Group value={lp} onChange={value => setLp(value as TimelineLabelPosition)}>
            <Radio.Button value="same">same</Radio.Button>
            <Radio.Button value="relative">relative</Radio.Button>
          </Radio.Group>
        </Space>
        <Space>
          <span>reverse</span>
          <Radio.Group value={reverse} onChange={v => seReverse(Boolean(v))}>
            <Radio.Button value={false}>normal</Radio.Button>
            <Radio.Button value={true}>reversed</Radio.Button>
          </Radio.Group>
        </Space>
      </Space>
      <Timeline space={sizeChangeProps.size} mode={mode} labelPosition={lp} reverse={reverse}>
        <Timeline.Item title="事件节点" label="2020-03-05 12:30" description="辅助信息，这里是流程节点的说明" />
        <Timeline.Item title="事件节点" label="2020-03-05 12:30" description="辅助信息，这里是流程节点的说明" />
        <Timeline.Item label="2020-03-05 12:30" description="辅助信息，这里是流程节点的说明" />
        <Timeline.Item
          status="notarrived"
          title="事件节点"
          label="2020-03-05 12:30"
          description="辅助信息，这里是流程节点的说明"
        />
      </Timeline>
      <Timeline space={sizeChangeProps.size} mode={mode} labelPosition={lp} reverse={reverse}>
        <Timeline.Item
          status="done"
          dotType="icon"
          title="事件节点"
          label="2020-03-05 12:30"
          description="辅助信息，这里是流程节点的说明"
        />
        <Timeline.Item
          dotType="icon"
          label="2020-03-05 12:30"
          status="current"
          description="辅助信息，这里是流程节点的说明"
        />
        <Timeline.Item dotType="icon" title="事件节点" status="notarrived" label="2020-03-05 12:30" />
      </Timeline>
      <Timeline space={sizeChangeProps.size} mode={mode} labelPosition={lp} reverse={reverse}>
        <Timeline.Item status="success" dotType="icon" title="成功节点" label="2020-03-05 12:30" />
        <Timeline.Item status="warning" dotType="icon" title="警示/出错节点" label="2020-03-05 12:30" />
        <Timeline.Item status="error" dotType="icon" title="失败节点" label="2020-03-05 12:30" />
      </Timeline>
      <Timeline space={sizeChangeProps.size} mode={mode} labelPosition={lp} reverse={reverse}>
        <Timeline.Item title="事件节点" label="2020-03-05 12:30" description="辅助信息，这里是流程节点的说明" />
        <Timeline.Item label="2020-03-05 12:30" status="current" description="辅助信息，这里是流程节点的说明" />
        <Timeline.Item title="事件节点" status="notarrived" label="2020-03-05 12:30" />
      </Timeline>
      <Timeline space={sizeChangeProps.size} mode={mode} labelPosition={lp} reverse={reverse}>
        <Timeline.Item status="success" title="成功节点" label="2020-03-05 12:30" />
        <Timeline.Item status="warning" title="警示/出错节点" label="2020-03-05 12:30" />
        <Timeline.Item status="error" title="失败节点" label="2020-03-05 12:30" />
      </Timeline>
    </Space>
  );
};

const TimeLabel = (
  <>
    <div>2020-03-05</div>
    <div>12:30</div>
  </>
);

